import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import projectService from '../../services/projectService';
import styles from './Projects.module.css';
import { FaArrowRight } from 'react-icons/fa';

function Projects() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadProjects = async () => {
      try {
        const data = await projectService.fetchProjects();
        setProjects(data);
      } catch (err) {
        setError('Unable to load projects at the moment.');
      } finally {
        setLoading(false);
      }
    };
    loadProjects();
  }, []);

  return (
    <main className={styles.projectsPage}>
      <div className={styles.container}>
        <header className={styles.header}>
          <h1>Our Projects</h1>
          <p>
            Explore our portfolio of scalable web applications, SaaS platforms, 
            and enterprise digital solutions.
          </p>
        </header>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '50px' }}>
            <p>Loading amazing projects...</p>
          </div>
        ) : error ? (
          <div style={{ textAlign: 'center', padding: '50px' }}>
            <p>{error}</p>
          </div>
        ) : projects.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '50px' }}>
            <p>No projects found. Check back later!</p>
          </div>
        ) : (
          <div className={styles.grid}>
            {projects.map((project) => (
              <div key={project._id} className={styles.projectCard}>
                <div className={styles.imageWrapper}>
                  <img src={project.images?.[0] || 'https://via.placeholder.com/400x250'} alt={project.title} />
                </div>
                <div className={styles.content}>
                  <h3>{project.title}</h3>
                  <p>{project.description?.substring(0, 120)}...</p>

                  <div className={styles.tags}>
                    {project.technologies?.map(tech => (
                      <span key={tech}>{tech}</span>
                    ))}
                  </div>

                  <Link to={`/projects/${project.slug}`} className={styles.viewBtn}>
                    View Details <FaArrowRight />
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}

export default Projects;
